package edu.valle.modules.cart.mapper;
import edu.valle.modules.cart.dto.response.*; import edu.valle.modules.cart.entity.*; import edu.valle.modules.inventory.repository.InventoryRepository; import java.math.*; import java.util.List; import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Component;
@Component @RequiredArgsConstructor public class CartMapper {private final InventoryRepository inventories;
 public CartResponse toResponse(Cart cart){List<CartItemResponse> items=cart.getItems().stream().map(this::item).toList();BigDecimal total=items.stream().map(CartItemResponse::subtotal).reduce(BigDecimal.ZERO,BigDecimal::add).setScale(2,RoundingMode.HALF_UP);return new CartResponse(cart.getId(),cart.getCustomer().getId(),items,total);}
 private CartItemResponse item(CartItem item){var v=item.getProductVariant();var p=v.getProduct();BigDecimal price=p.getSalePrice().setScale(2,RoundingMode.HALF_UP);BigDecimal subtotal=price.multiply(BigDecimal.valueOf(item.getQuantity())).setScale(2,RoundingMode.HALF_UP);int stock=inventories.findByProductVariantId(v.getId()).map(i->i.getCurrentStock()).orElse(0);return new CartItemResponse(item.getId(),v.getId(),p.getId(),p.getName(),v.getSize(),v.getColor(),price,item.getQuantity(),subtotal,stock);}}
